import React, { useState, useEffect } from 'react';
import axios from 'axios';

function Admin() {
  const [projects, setProjects] = useState([]);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [password, setPassword] = useState('');
  const [editingProject, setEditingProject] = useState(null);
  const adminPassword = "admin123"; // Change this for security

  const API_URL = 'http://localhost:5000/api';

  const fetchData = async () => {
    try {
      const res = await axios.get(`${API_URL}/requests`);
      setProjects(res.data);
    } catch (err) {
      console.error("Error fetching data:", err);
    }
  };

  useEffect(() => {
    if (isLoggedIn) fetchData();
  }, [isLoggedIn]);

  const handleLogin = (e) => {
    e.preventDefault();
    if (password === adminPassword) setIsLoggedIn(true);
    else alert("Incorrect Password!");
  };

  const handleUpdate = async (e) => {
    e.preventDefault();
    try {
      await axios.put(`${API_URL}/update-status/${editingProject._id}`, editingProject);
      alert("✅ Project Updated Successfully!");
      setEditingProject(null);
      fetchData();
    } catch (err) {
      alert("❌ Update failed!");
    }
  };

  // Logic to mark a project as fully paid with one click
  const handleMarkFullPaid = async (proj) => {
    if (window.confirm(`Mark ${proj.fullName} as Fully Paid?`)) {
      try {
        await axios.put(`${API_URL}/update-status/${proj._id}`, {
          ...proj,
          advancePaid: proj.totalBudget, // Set paid amount equal to budget
          paymentStatus: "Paid"
        });
        fetchData();
      } catch (err) {
        alert("❌ Failed to update payment.");
      }
    }
  };

  const handleResolveRevision = async (id) => {
    try {
      await axios.put(`${API_URL}/update-status/${id}`, { revisionsRequested: "" });
      fetchData();
    } catch (err) {
      alert("❌ Error resolving revision.");
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm("Are you sure you want to delete this project?")) {
      try {
        await axios.delete(`${API_URL}/delete-request/${id}`);
        fetchData();
      } catch (err) {
        alert("❌ Delete failed!");
      }
    }
  };

  if (!isLoggedIn) {
    return (
      <div className="d-flex justify-content-center align-items-center bg-light" style={{ minHeight: '100vh' }}>
        <div className="card shadow border-0 p-4" style={{ width: '350px', borderRadius: '15px' }}>
          <h4 className="text-center fw-bold mb-4">Admin Login</h4>
          <form onSubmit={handleLogin}>
            <input 
              type="password" 
              placeholder="Enter Password" 
              className="form-control mb-3 text-center" 
              value={password} 
              onChange={(e) => setPassword(e.target.value)} 
              required 
            />
            <button className="btn btn-dark w-100 fw-bold py-2 shadow">Login to Dashboard</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="container-fluid py-4 px-lg-5 bg-light" style={{ minHeight: '100vh' }}>
      <div className="d-flex justify-content-between align-items-center mb-4">
        <div>
          <h2 className="fw-bold m-0 text-dark">Freelance Project Manager</h2>
          <p className="text-muted small">Manage clients, payments, and revisions in real-time.</p>
        </div>
        <button className="btn btn-outline-danger btn-sm px-4 rounded-pill fw-bold" onClick={() => setIsLoggedIn(false)}>Logout</button>
      </div>

      <div className="card border-0 shadow-sm rounded-4 overflow-hidden">
        <table className="table table-hover mb-0 align-middle">
          <thead className="bg-dark text-white">
            <tr className="small text-uppercase">
              <th className="py-3 ps-4">Client / Service</th>
              <th>Progress</th>
              <th>Financials</th>
              <th>Revision Request</th>
              <th>Project Status</th>
              <th className="text-end pe-4">Actions</th>
            </tr>
          </thead>
          <tbody>
            {projects.map((proj) => {
              const budget = Number(proj.totalBudget) || 0;
              const paid = Number(proj.advancePaid) || 0;
              const balance = budget - paid;
              const isSettled = budget > 0 && balance <= 0;

              return (
                <tr key={proj._id}>
                  <td className="ps-4">
                    <div className="fw-bold text-dark">{proj.fullName}</div>
                    <div className="text-primary small fw-semibold">{proj.serviceType}</div>
                  </td>
                  <td>
                    <div className="progress mb-1" style={{ height: '6px', width: '100px' }}>
                      <div className="progress-bar bg-success" style={{ width: `${proj.progress}%` }}></div>
                    </div>
                    <span className="small fw-bold">{proj.progress}%</span>
                  </td>

                  {/* PROFESSIONAL FINANCIAL SECTION */}
                  <td style={{ minWidth: '160px' }}>
                    {isSettled ? (
                      <div className="p-2 rounded bg-success-subtle border border-success text-center shadow-sm" style={{ width: '140px' }}>
                        <span className="text-success fw-bold small">✅ FULLY PAID</span>
                        <div className="text-muted small" style={{ fontSize: '10px' }}>Total: ₹{budget}</div>
                      </div>
                    ) : (
                      <div className="small">
                        <div className="d-flex justify-content-between mb-1">
                          <span className="text-muted">Budget:</span> <b>₹{budget}</b>
                        </div>
                        <div className="d-flex justify-content-between mb-1">
                          <span className="text-muted">Paid:</span> <b className="text-success">₹{paid}</b>
                        </div>
                        <div className="d-flex justify-content-between border-top pt-1 text-danger fw-bold">
                          <span>Rem:</span> <span>₹{balance}</span>
                        </div>
                        <button 
                          className="btn btn-outline-success btn-xs w-100 mt-2 py-0 fw-bold" 
                          style={{ fontSize: '10px' }}
                          onClick={() => handleMarkFullPaid(proj)}
                        >
                          Mark Paid
                        </button>
                      </div>
                    )}
                  </td>

                  <td>
                    {proj.revisionsRequested ? (
                      <div className="bg-warning-subtle p-2 border border-warning rounded shadow-sm" style={{ maxWidth: '180px' }}>
                        <div className="small text-dark mb-2 text-wrap">"{proj.revisionsRequested}"</div>
                        <button className="btn btn-success btn-sm w-100 py-0 fw-bold shadow-sm" style={{ fontSize: '10px' }} onClick={() => handleResolveRevision(proj._id)}>DONE</button>
                      </div>
                    ) : <span className="text-muted small">No Requests</span>}
                  </td>

                  <td>
                    <span className={`badge rounded-pill px-3 ${proj.status === 'Completed' ? 'bg-success border border-success' : 'bg-warning text-dark border border-warning'}`}>
                      {proj.status}
                    </span>
                  </td>

                  <td className="text-end pe-4">
                    <button className="btn btn-sm btn-light border me-2 shadow-sm fw-bold" onClick={() => setEditingProject(proj)}>Edit</button>
                    <button className="btn btn-sm btn-outline-danger shadow-sm fw-bold" onClick={() => handleDelete(proj._id)}>Delete</button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {/* QUICK EDIT MODAL */}
      {editingProject && (
        <div className="modal show d-block" style={{ backgroundColor: 'rgba(0,0,0,0.6)' }}>
          <div className="modal-dialog modal-dialog-centered">
            <div className="modal-content border-0 rounded-4 shadow">
              <div className="modal-header border-0 bg-light rounded-top-4 pb-0">
                <h5 className="fw-bold">Edit Project Details</h5>
                <button type="button" className="btn-close" onClick={() => setEditingProject(null)}></button>
              </div>
              <form onSubmit={handleUpdate}>
                <div className="modal-body py-4">
                  <div className="row g-3">
                    <div className="col-6">
                      <label className="small fw-bold text-secondary">Total Budget (₹)</label>
                      <input type="number" className="form-control" value={editingProject.totalBudget} onChange={(e) => setEditingProject({ ...editingProject, totalBudget: e.target.value })} />
                    </div>
                    <div className="col-6">
                      <label className="small fw-bold text-secondary">Paid Amount (₹)</label>
                      <input type="number" className="form-control" value={editingProject.advancePaid} onChange={(e) => setEditingProject({ ...editingProject, advancePaid: e.target.value })} />
                    </div>
                    <div className="col-6">
                      <label className="small fw-bold text-secondary">Progress (%)</label>
                      <input type="number" className="form-control" value={editingProject.progress} onChange={(e) => setEditingProject({ ...editingProject, progress: e.target.value })} />
                    </div>
                    <div className="col-6">
                      <label className="small fw-bold text-secondary">Current Status</label>
                      <select className="form-select" value={editingProject.status} onChange={(e) => setEditingProject({ ...editingProject, status: e.target.value })}>
                        <option value="Pending">Pending</option>
                        <option value="In Progress">In Progress</option>
                        <option value="Completed">Completed</option>
                      </select>
                    </div>
                  </div>
                </div>
                <div className="modal-footer border-0 bg-light rounded-bottom-4">
                  <button type="submit" className="btn btn-dark w-100 fw-bold py-2 shadow">Save All Changes</button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default Admin;
